<?php
require_once('config.inc.php');

header("Access-Control-Allow-Origin: *");
header("Access-Control-Allow-Methods: GET, POST, OPTIONS");
header("Access-Control-Allow-Headers: Content-Type, cache-control, Authorization, X-Requested-With, satoken, Token");
header("Content-Type: application/json; charset=utf-8");
header('Cache-Control: no-cache');

// 处理 OPTIONS 请求
if ($_SERVER['REQUEST_METHOD'] == 'OPTIONS') {
    exit;
}

$_POST = json_decode(file_get_contents("php://input"), true);
//print_R(json_encode($_POST));


$pptxProperty = "";

$pptxProperty = base64_decode($pptxProperty);

// 解压缩 Gzip 数据
$json = gzdecode($pptxProperty);

// 解析解压后的 JSON 数据
$_pptxObj = json_decode($json, true);

// 输出解压后的数据
//print_r($_pptxObj);

$pptxProperty = base64_encode(gzencode(json_encode($_pptxObj)));

$RS             = [];
$RS['code']     = 0;
$RS['message']  = 'ok';
$RS['data']['current'] = 8;
$RS['data']['total'] = 15;
$RS['data']['pptxProperty'] = $pptxProperty;

print_R(json_encode($RS));
?>
